DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGchoicemacros.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
Context()->operators->redefine('>',using=>',',from=>'Numeric');
Context()->lists->set('List' => {separator => '>'});

@a = (1..99)[NchooseK(99, 5)];
@a = map{Real($_/10)} (@a);
# make two or three negative
$a[0] = -$a[0];
$a[1] = -$a[1];
$a[2] = list_random($a[2], -$a[2]);
# make two of the negatives close together
do {
  $a[1] = $a[0] + non_zero_random(-1,1,0.1);
} until (0 > $a[1] && $a[1] != $a[2]);
# shuffle
@a = (@a)[NchooseK(5,5)];
$as = join('\enspace', map{'{' . $_ . '}'} (@a));
@b = PGsort(sub{$_[0] > $_[1]}, @a);
$bs = join('>', @b);

$comparison = Compute("$bs");

############################################################
# Body
############################################################

BEGIN_PGML
Use the [`\newcommand{\gt}{>}\gt`] symbol to arrange the following numbers in order from greatest to least. For example, your answer might look like [`\newcommand{\gt}{>}4 \gt 3 \gt 2 \gt 1 \gt 0\text{.}`]

[`[$as]`]

[_]{$comparison}{30}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
